// Turn the plain-English business type into an OpenStreetMap tag,
// combine with geocoded lat/lon, and build the Overpass QL query.
const config = $('Get Config').first().json;
const geo = items[0].json[0];
if (!geo) {
  throw new Error('Location not found by Nominatim: ' + config.location + ' — try a broader or differently spelled location.');
}
const lat = geo.lat;
const lon = geo.lon;

const tagMap = {
  restaurant: 'amenity=restaurant', restaurants: 'amenity=restaurant',
  cafe: 'amenity=cafe', cafes: 'amenity=cafe', coffee: 'amenity=cafe',
  dentist: 'amenity=dentist', dentists: 'amenity=dentist',
  doctor: 'amenity=doctors', doctors: 'amenity=doctors', clinic: 'amenity=clinic',
  hospital: 'amenity=hospital', hospitals: 'amenity=hospital',
  pharmacy: 'amenity=pharmacy', pharmacies: 'amenity=pharmacy', chemist: 'amenity=pharmacy',
  hotel: 'tourism=hotel', hotels: 'tourism=hotel',
  gym: 'leisure=fitness_centre', gyms: 'leisure=fitness_centre', fitness: 'leisure=fitness_centre',
  bank: 'amenity=bank', banks: 'amenity=bank',
  electrician: 'craft=electrician', electricians: 'craft=electrician',
  plumber: 'craft=plumber', plumbers: 'craft=plumber',
  lawyer: 'office=lawyer', lawyers: 'office=lawyer',
  school: 'amenity=school', schools: 'amenity=school',
  supermarket: 'shop=supermarket', supermarkets: 'shop=supermarket', grocery: 'shop=supermarket',
  hairdresser: 'shop=hairdresser', salon: 'shop=hairdresser', barber: 'shop=hairdresser',
  bakery: 'shop=bakery', bakeries: 'shop=bakery',
  bookstore: 'shop=books',
  mechanic: 'shop=car_repair',
  realestate: 'office=estate_agent',
  accountant: 'office=accountant', accountants: 'office=accountant'
};

const q = (config.query || '').toLowerCase().trim();
const tag = tagMap[q];
let filter;
if (tag) {
  const [k, v] = tag.split('=');
  filter = `["${k}"="${v}"]`;
} else {
  // fallback: no exact tag match, search business names containing the keyword
  filter = `["name"~"${config.query}",i]`;
}

const radius = config.radius_meters || 5000;
const wanted = (config.leads_per_run || 10) * 3; // over-fetch since some results lack a name
const query = `[out:json][timeout:25];(node${filter}(around:${radius},${lat},${lon});way${filter}(around:${radius},${lat},${lon}););out center ${wanted};`;

return [{ json: { overpassQuery: query } }];

const config = $('Get Config').first().json;
const limit = config.leads_per_run || 10;
const elements = items[0].json.elements || [];

function addr(tags) {
  const parts = [tags['addr:housenumber'], tags['addr:street'], tags['addr:city']].filter(Boolean);
  return parts.length ? parts.join(', ') : (tags['addr:full'] || '');
}

const leads = elements
  .filter(e => e.tags && e.tags.name)
  .slice(0, limit)
  .map(e => ({
    place_id: 'osm-' + e.type + '-' + e.id,
    name: e.tags.name,
    address: addr(e.tags),
    phone: e.tags.phone || e.tags['contact:phone'] || '',
    website: e.tags.website || e.tags['contact:website'] || '',
    category: e.tags.amenity || e.tags.shop || e.tags.office || e.tags.craft || e.tags.tourism || e.tags.leisure || '',
    rating: ''
  }));

return leads.map(l => ({ json: l }));
